import pymysql
import os
import json
from flask import Request

def query_database(request: Request):
    db_user = os.environ.get('DB_USER', 'root')
    db_password = os.environ.get('DB_PASSWORD', '')
    db_name = os.environ.get('DB_NAME', 'mydb')
    db_host = os.environ.get('DB_HOST', '127.0.0.1')
    db_port = int(os.environ.get('DB_PORT', 3306))
    
    connection = None
    try:
        connection = pymysql.connect(
            host=db_host,
            port=db_port,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor
        )
        
        if request.method == 'GET':
            params = request.args
        elif request.method == 'POST':
            params = request.get_json() if request.is_json else request.form
        else:
            return {'error': 'Method not allowed'}, 405
        
        table = params.get('table', 'users')
        
        query = f"SELECT * FROM {table}"
        conditions = []
        
        search_fields = ['name', 'email', 'status', 'category', 'department', 'role', 'city', 'country']
        for field in search_fields:
            if field in params and params[field]:
                conditions.append(f"{field} = '{params[field]}'")
        
        like_fields = ['search', 'keyword', 'text']
        for field in like_fields:
            if field in params and params[field]:
                search_value = params[field]
                search_columns = params.get('search_columns', 'name,description').split(',')
                like_conditions = [f"{col} LIKE '%{search_value}%'" for col in search_columns]
                conditions.append(f"({' OR '.join(like_conditions)})")
        
        numeric_fields = ['id', 'age', 'price', 'quantity', 'year']
        for field in numeric_fields:
            if field in params and params[field]:
                conditions.append(f"{field} = {params[field]}")
            
            min_field = f'min_{field}'
            max_field = f'max_{field}'
            if min_field in params and params[min_field]:
                conditions.append(f"{field} >= {params[min_field]}")
            if max_field in params and params[max_field]:
                conditions.append(f"{field} <= {params[max_field]}")
        
        date_fields = ['created_at', 'updated_at', 'date', 'start_date', 'end_date']
        for field in date_fields:
            start_field = f'{field}_start'
            end_field = f'{field}_end'
            if start_field in params and params[start_field]:
                conditions.append(f"{field} >= '{params[start_field]}'")
            if end_field in params and params[end_field]:
                conditions.append(f"{field} <= '{params[end_field]}'")
        
        if conditions:
            query += " WHERE " + " AND ".join(conditions)
        
        if 'order_by' in params:
            order_by = params['order_by']
            direction = params.get('order_direction', 'ASC')
            query += f" ORDER BY {order_by} {direction}"
        
        if 'limit' in params:
            query += f" LIMIT {params['limit']}"
            if 'offset' in params:
                query += f" OFFSET {params['offset']}"
        
        with connection.cursor() as cursor:
            cursor.execute(query)
            results = cursor.fetchall()
        
        return {
            'success': True,
            'data': results,
            'count': len(results),
            'query': query
        }, 200
        
    except Exception as e:
        return {
            'success': False,
            'error': str(e)
        }, 500
        
    finally:
        if connection:
            connection.close()